var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":["stopWordFilter"],"fields":{"title":{"boost":1000.0},"text":{"boost":1.0},"tags":{"boost":1000000.0}}},"docs":[{"location":"index.html","title":"Welcome","text":"<p>Read at gerald1248.github.io/cookbook/.</p>"},{"location":"index.html#bring-your-own-recipes","title":"Bring your own recipes","text":"<p>Fork the repository and add a pull request!</p> <p>Go to: GitHub repository</p> <p>Tip</p> <p>You can download these pages as a single PDF.</p>"},{"location":"breakfast/courgette-fritters.html","title":"Courgette fritters","text":""},{"location":"breakfast/courgette-fritters.html#ingredients","title":"Ingredients","text":"<p>500g courgettes, grated 2tsp fine salt 2tsp onion powder  2tsp onion granules  1 heaped Tbsp gram flour + 3Tbsp warm water (replaces 1 eggs) 30g potato starch 25g oat flour</p>"},{"location":"breakfast/courgette-fritters.html#method","title":"Method","text":"<p>Grate courgettes. Mix w 2 tsp fine salt. Transfer mix to fine sieve and place sieve over bowl. Let liquid drain, push liquid out w a large spoon and applying pressure. Once most liquid has drained, tip out liquid and put grated and salted courgettes back in the bowl.</p> <p>Add gram egg. Mix well. Mix onion powder, granules, potato starch and  oat flour. Add the dry mix to the bowl. Mix some more and let rest for 15 mins.</p> <p>Fry in small portions (slightly heaped Tbsp) from both sides medium heat</p>"},{"location":"breakfast/pancakes.html","title":"Pancakes thin / thick","text":""},{"location":"breakfast/pancakes.html#ingredients","title":"Ingredients","text":"<p>210g white flour 70g wholegrain flour (optional, can be replaced w 80g white flour) 1.5 / 2.5 tsp baking powder (thin / thick) 1 tsp vanilla extract  28g melted butter / neutral oil (if using wholegrain flour, otherwise optional) 60g sugar 470 / 600ml (soy) milk (thick / thin)</p>"},{"location":"breakfast/pancakes.html#method","title":"Method","text":"<p>Mix dry ingredients. Add 330ml soy milk and mix, this is it avoid clumps. Add remaining milk (140ml for thick, 270ml for thin). Add vanilla extract and melted butter / oil. Stir carefully. Let batter rest for 5-10 mins. </p> <p>Heat frying pan. Add thin coating of oil w silicon brush. Add pancake batter and tilt the pan to make thinner pancakes.</p>"},{"location":"breakfast/potato-fritters.html","title":"Potato Fritters","text":""},{"location":"breakfast/potato-fritters.html#ingredients","title":"Ingredients","text":"<p>750g potatoes, grated 2tsp fine salt 2tsp onion powder  2tsp onion granules  3 heaped Tbsp gram flour + 9Tbsp warm water (replaces 3 eggs) 35g oat flour</p>"},{"location":"breakfast/potato-fritters.html#method","title":"Method","text":"<p>Grate potatoes. Mix w 2 tsp fine salt. Transfer mix to fine sieve and place sieve over bowl. Let liquid drain, push liquid out w a large spoon and applying pressure. Once most liquid has drained, tip out liquid and put grated and salted potatoes back in the bowl.</p> <p>Add onion powder and granules plus gram eggs. Mix well. Add oat flour. Mix some more and let rest for 15 mins. Fry in small portions (slightly heaped Tbsp) from both sides medium heat</p>"},{"location":"breakfast/wunderbroed.html","title":"Wunderbroed Scandinavian Bread","text":"<p>Also: Wunderbrot, Wunder Broed</p>"},{"location":"breakfast/wunderbroed.html#ingredients","title":"Ingredients","text":"<p>Psyllium husk Oats Gluten free bread</p>"},{"location":"salad/mustard-dressing.html","title":"Mayonnaise Mustard Dressing","text":""},{"location":"salad/mustard-dressing.html#ingredients","title":"Ingredients","text":"<p>100g mayonnaise, vegan Hellmann\u2019s 100g / ml soya milk 10g Dijon mustard, Maille 8g salt</p>"},{"location":"salad/mustard-dressing.html#method","title":"Method","text":"<p>Put all ingredients into a jar with a lid and shake or mix them in a bowl / glass w a fork</p>"},{"location":"savoury/hummus.html","title":"Hummus","text":"<p>Makes: 800g hummus</p>"},{"location":"savoury/hummus.html#ingredients","title":"Ingredients","text":"<p>480g chickpeas (2 tins drained and washed) 170g tahini 103 ml/g water 47ml/g lemon juice 1 clove of garlic 2-2.5 tsp of salt</p>"},{"location":"savoury/hummus.html#method","title":"Method","text":"<p>Pur\u00e9e all but the chickpeas first. Then add half the chickpeas and puree until smooth. Add the second half of chickpeas and puree until smooth or leave some coarseness</p>"},{"location":"savoury/kidney-bean-leberwurst-vegan.html","title":"Kidney Bean Smoked Tofu Leberwurst Vegan","text":"<p>Taken from: cheapandcheerfulcooking</p>"},{"location":"savoury/kidney-bean-leberwurst-vegan.html#ingredients","title":"Ingredients","text":"<p>1 can kidney beans, 240g drained weight 150g smoked tofu 1 onion, small 2 tsp marjoram 1 tsp mustard 1 tsp smoked salt, alternatively regular salt 1/2 tsp pepper 2 tbsp vegetable oil, e.g. rapeseed oil</p>"},{"location":"savoury/kidney-bean-leberwurst-vegan.html#preparation","title":"Preparation","text":"<ol> <li> <p>Finely dice the onion and saut'e in a pan with a dash of vegetable oil at medium temperature for  a few minutes. Add marjoram and sweat briefly. Remove from the heat and let cool down a bit.</p> </li> <li> <p>Drain the beans well. Roughly crumble the tofu. Mix with all the other ingredients in a food processor or with the help of a hand blender until the vegan liver sausage has the desired consistency. If necessary, add a few drops of water in the course of this.</p> </li> </ol>"},{"location":"savoury/veganes-mett.html","title":"Veganes Mett","text":"<p>See www.zuckerjagdwurst.com.</p>"},{"location":"savoury/veganes-mett.html#zutaten","title":"Zutaten","text":"<p>100 g Reiswaffeln 250 - 300 ml Wasser 1/2 - 1 helle Zwiebel 50 g Tomatenmark Salz&amp;Pfeffer 2 St\u00e4ngel Petersilie 4 helle Br\u00f6tchen</p>"},{"location":"savoury/veganes-mett.html#zubereitung","title":"Zubereitung","text":"<p>Die Reiswaffeln in einer Schale mit den Finger zerkleinern.</p> <p>Das Wasser hinzugeben und nach und nach mit einer Gabel unterheben, sodass sich das Wasser gut verteilen kann. Einweichen lassen.</p> <p>Die Enden der Zwiebeln abschneiden, die Schale entfernen und die Zwiebel w\u00fcrfeln.</p> <p>Zwiebelw\u00fcrfel und Tomatenmark zu der eingeweichten Reiswaffel geben und mit einer Gabel unterheben und gut verteilen.</p> <p>Gut salzen und pfeffern. Anschlie\u00dfend am besten ein paar Stunden im K\u00fchlschrank durchziehen lassen.</p>"},{"location":"soup/lemony-lentil.html","title":"Lemony Lentil &amp; Chard Soup","text":"<p>This satisfying lemony bowlful was inspired by the lentil soup served at the now-closed Lebanese restaurant La Shish in West Bloomfield, Michigan. It keeps well but will thicken, so you may want to thin it with a bit of water or broth when reheating. Serve with warm whole-wheat pita.</p> <p>By Carolyn Malcoun  Updated on September 21, 2025</p> <p>Reviewed by Dietitian Breana Lai Killeen, M.P.H., RD</p>"},{"location":"soup/lemony-lentil.html#method","title":"Method","text":"<p>Active Time: 30 mins Total Time: 55 mins Servings: 6 </p>"},{"location":"soup/lemony-lentil.html#nutrition-profile","title":"Nutrition Profile","text":"<p>Mediterranean Diet Dairy-Free Soy-Free High-Fiber Vegan Vegetarian High-Protein Egg-Free Gluten-Free Low-Calorie</p>"},{"location":"soup/lemony-lentil.html#ingredients","title":"Ingredients","text":"<p>3 tablespoons extra-virgin olive oil, plus more for serving</p> <p>1 large onion, diced</p> <p>1 bunch chard</p> <p>4 cloves garlic, finely chopped</p> <p>1 tablespoon ground cumin</p> <p>\u00bd teaspoon Aleppo pepper, plus more for serving</p> <p>8 cups water</p> <p>1 pound red lentils, picked over and rinsed</p> <p>1 \u00bd teaspoons salt</p>"},{"location":"sweet/frangipane.html","title":"Frangipane (Almond Cream)","text":"<p>Frangipane, a staple of classic French pastry, is a creamy, sweet, almondy filling that\u2019s surprisingly easy to make and has many uses. This frangipane recipe uses simple ingredients like butter, sugar, eggs, and almond flour to ensure the almond flavor shines through. Spread frangipane into a tart shell, pipe it into croissant dough to make a decadent breakfast pastry, or spread it onto brioche to make Bostock.</p>"},{"location":"sweet/frangipane.html#preparation","title":"Preparation","text":"<p>5 mins</p>"},{"location":"sweet/frangipane.html#total","title":"Total","text":"<p>5 mins</p>"},{"location":"sweet/frangipane.html#yield","title":"Yield","text":"<p>about 1 3/4 cups</p> <p>Frangipane (Almond Cream) Ingredients</p> <p>6 tablespoons (85g) unsalted butter, at room temperature 1/2 cup (99g) granulated sugar 1/4 teaspoon table salt 1 cup (96g) King Arthur Almond Flour 3 tablespoons (23g) King Arthur Unbleached All-Purpose Flour or King Arthur Gluten-Free Measure for Measure Flour 1 large egg, at room temperature 2 teaspoons almond emulsion or almond extract Instructions</p> <p>In a medium bowl or the bowl of a stand mixer, beat together the butter, sugar, and salt until pale and fluffy, about 1 minute on medium speed.</p> <p>Stir in the flours, egg, and almond flavoring. Mix until just combined.</p> <p>Use the frangipane as desired: fill tart shells, pipe into croissant dough, top slices of Bostock, or come up with your own way to use this flavorful, nutty filling. Bake the frangipane as directed in your recipe or until it\u2019s golden brown and smells nutty.</p> <p>Store leftover unbaked frangipane in the refrigerator, covered, for up to 1 week or freeze for up to 2 months.</p>"}]}